import React, { useState } from 'react';
import axios from "axios";
import { useNavigate } from 'react-router-dom';  // Import useNavigate
import styles from '../styles/styles.css';

const RegisterPage = () => {
    const [email, setEmail] = useState('');
    const [name, setName] = useState('');
    const [phone, setPhone] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');
    const [data, setData] = useState('');

    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!email || !password || !confirmPassword || !phone || !name) {
            setError('Please fill out all fields');
            return;
        }

        if (password !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        console.log('Registering with', { email, password });

        // let response = null;
        const register = async () => {
            let response = await axios.post("http://localhost:3003/user/register", {
                name: name,
                password: password,
                email: email,
                phone: phone,
            })

            setData(response);

            if (200 !== response.status) {
                console.log("200 !== response.status). response: " + response);
                setError(response.message);
                // throw new Error('Registration failed, please try again.');
            }

            console.log("esponse.data.token: " + response.data.token);
            sessionStorage.setItem('token', response.data.token);
        }

        try {
            await register();
        } catch (error) {
            console.log("error is: " + error);
            console.log("data is: " + data);
            setError(error);
            navigate('/');
        }

        // sessionStorage.setItem('token', response.data.token);

        navigate('/profile');
    };

    return (
        <div style={styles.container}>
            <h2>Create an Account</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit}>
                <div style={styles.inputContainer}>
                    <label>Name</label>
                    <input
                        type="name"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your name"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Email</label>
                    <input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your email"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your password"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Confirm Password</label>
                    <input
                        type="password"
                        value={confirmPassword}
                        onChange={(e) => setConfirmPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Confirm your password"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Phone</label>
                    <input
                        type="phone"
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your phone number"
                    />
                </div>
                <button type="submit" style={styles.button}>Register</button>
            </form>
            <div style={styles.redirect}>
                <p>Already have an account? <a href="/login">Login here</a></p>
            </div>
        </div>
    );
};

